function getProfile(genre) {
  return Object.values(sceneProfiles).find((profile) =>
    profile.genres.includes(genre),
  );
}

const genreFamilies = {
  "French House": ["French House", "Electro House", "House", "Deep House", "Progressive House"],
  "Chicago House": ["Chicago House", "House", "Acid House", "Deep House"],
  House: ["House", "Chicago House", "French House", "Deep House", "Progressive House"],
  "Acid House": ["Acid House", "Chicago House", "House", "Detroit Techno"],
  "Detroit Techno": ["Detroit Techno", "Techno", "Acid House", "Electronic"],
  "Electro House": ["Electro House", "French House", "House"],
  "Trip Hop": ["Trip Hop", "Downtempo"],
  Downtempo: ["Downtempo", "Trip Hop", "Ambient House", "Ambient Techno"],
  "Synth-pop": ["Synth-pop", "Electronic"],
  Disco: ["Disco", "Dance", "House"],
  Dance: ["Dance", "Disco", "House"],
  "Acid Jazz": ["Acid Jazz", "Jazz Rap"],
  "Jazz Rap": ["Jazz Rap", "Acid Jazz"],
  "Big Beat": ["Big Beat", "Electronic"],
  Electronic: ["Electronic", "IDM", "Ambient Techno", "Techno"],
  IDM: ["IDM", "Electronic", "Ambient Techno"],
  "Ambient House": ["Ambient House", "Ambient Techno", "Downtempo"],
  "Ambient Techno": ["Ambient Techno", "Ambient House", "Downtempo", "IDM"],
  Techno: ["Techno", "Detroit Techno", "Electronic"],
  "Progressive House": ["Progressive House", "House", "Deep House", "French House"],
  "Deep House": ["Deep House", "House", "Chicago House", "Progressive House"],
};

const questions = catalog.map(([artist, title, year, genre], index) => {
  const profile = getProfile(genre);
  const relatedGenres = genreFamilies[genre] ?? [genre];
  const alternatives = catalog
    .filter((track) => relatedGenres.includes(track[3]) && track[1] !== title)
    .map((track) => track[1])
    .slice(0, 3);

  return {
    id: index + 1,
    artist,
    title,
    year,
    genre,
    album: albums[index],
    sottogenere: profile.sottogenere,
    paese: countries[index],
    scenarioCulturale: `${artist} pubblicò "${title}" nel ${year}. ${profile.scenario}`,
    significato: `${profile.significato} Nel catalogo di ${artist}, "${title}" ne rappresenta una sintesi particolarmente riconoscibile.`,
    influenzeMusicali: [...profile.influenze],
    artistiInfluenzati: profile.influenzati.filter(
      (influencedArtist) => influencedArtist !== artist,
    ),
    question: "Qual è il titolo del brano?",
    answers: [title, ...alternatives],
    correctAnswer: title,
    preview: "",
  };
});

function track(id, artist, title, year, genre, album, sottogenere, paese, distrattori, contesto, importanza, tratti, influenze, influenzati, scena) {
  return { id, artist, title, year, genre, album, sottogenere, paese, distrattori, contesto, importanza, tratti, influenze, influenzati, scena };
}

